  ('social-worker-moex-04912', 'social-worker', 'social-worker-moex-108-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '確認兩變項因果關係的條件之一是發生的時間順序，已知變項X發生的時間在先，變項Y發生 於後，下列敘述何者最正確？', '["變項Y並非變項X的因", "變項X並非變項Y的因", "變項Y是變項X的因", "變項X是變項Y的因"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "00b091c10e58", "answer_pdf_sha1": "fa23129d5204", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
