  ('social-worker-moex-04918', 'social-worker', 'social-worker-moex-108-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某位研究者想了解社工員開案時的會談取向對於案主的影響。該研究者收集了30個開案會談錄 音，轉成逐字稿，並依理論架構界定出五大類別，然後將這些會談分類。再請另外兩位研究者針 對這30個開案會談資料分到五大類中。此舉可評估下列何種信度？', '["折半信度", "再測信度", "複本信度", "評分者間信度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "00b091c10e58", "answer_pdf_sha1": "fa23129d5204", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
